import { NextResponse } from "next/server";
import { createServerSupabase } from "@/lib/supabase/server";
import {
  buildWorkerLogPath,
  findRunStamp,
  getJob,
  updateJob,
} from "@/lib/bulk-jobs";
import { streamLogFile } from "@/lib/bulk-job-stream";

export const runtime = "nodejs";

export async function GET(
  _request: Request,
  context: { params: Promise<{ jobId: string; workerId: string }> }
) {
  const { jobId, workerId: workerParam } = await context.params;
  const supabase = await createServerSupabase();
  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { data: settings } = await supabase
    .from("partner_user_settings")
    .select("is_admin")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!settings?.is_admin) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  const job = getJob(jobId);
  if (!job) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  const workerId = Number(workerParam);
  if (!Number.isFinite(workerId) || workerId < 1) {
    return NextResponse.json({ error: "Invalid worker id." }, { status: 400 });
  }

  let cachedStamp = job.runStamp ?? null;
  const getPath = () => {
    if (!cachedStamp) {
      const detected = findRunStamp(job);
      if (detected) {
        cachedStamp = detected;
        updateJob(job.jobId, (current) => ({
          ...current,
          runStamp: detected,
        }));
      }
    }
    if (!cachedStamp) return null;
    return buildWorkerLogPath(cachedStamp, workerId);
  };

  return streamLogFile(getPath, { worker: `w${workerId}` });
}
